INSERT INTO public.om_activity_years (activity_code, fiscal_year, service, appropriation, ba, sag_short_code, title, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$OM_NAVY_X_469$$, 2026, $$Navy$$, $$OM_NAVY$$, NULL, NULL, $$Department of the Navy$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$, 3B1K
         524                                                                                                                                                          (Page 15 of 15)
                                                                              Department of the Navy
                                                                      FY 2026 President's Budget Submission
                                                                         Operation and Maintenance, Navy
                                                                      Budget Activity: Training and Recruiting
                                                                Activity Group: Basic Skills And Advanced Training
                                                         Detail by Subactivity Group: Professional Development Education
I. Description of Operations Financed:

Professional Development Education prepares career officers for more demanding assignments, particularly command and staff positions. It is concerned with broad professional
goals in subjects such as military science, engineering, and management.

The Naval War College (NWC) includes the Department's senior and intermediate colleges and is organized into three academic departments: Strategy and Policy, National
Security and Decision Making and Joint Military Operations. In addition, NWC houses the Center for War-gaming and the Strategic Studies Group, and provides the resident
education for foreign naval officers. The distance education program closely parallels the resident curriculum and is offered via various methodologies--Fleet Seminars, Web-
Enabled courses and CD-ROMs.

Navy Professional Military Education (NPME) is an integral component of the Professional Military Education (PME) continuum. NPME supports fleet requirements for
fundamental, intermediate and professional knowledge for all Sailors, officer and enlisted, through the following core competencies: Navy/military studies, professionalism, and
national and global security. NPME courses assist in growth and career-long development from accession through the executive levels of Navy service.

The Naval Postgraduate School (NPS) is an accredited institution offering graduate degree programs with specific defense emphasis, particularly in science, engineering and
technical areas. It also maintains a graduate level research program that responds to the emerging needs of the Navy.

The United States Naval Community College (USNCC) was established by the Secretary of the Navy in 2019 to increase naval educational opportunities for over 450,000 active-
duty Sailors and Marines. USNCC is establishing academic programs in technical and non-technical fields, which are relevant to the current and future needs of the Navy and
Marine Corps, including in designated fields of national and economic importance such as cybersecurity, artificial intelligence, machine learning, data science, and software
engineering. Programs would also incorporate critical 21st Century skills through instruction in the fields of the liberal arts and sciences. USNCC is addressing student success and
learning outcomes by developing remedial, developmental, or continuing education programs and support and advisement services for individuals pursuing such programs and
continuous monitoring of the progress of USNCC students. USNCC is also pursuing academic accreditation for its degree programs.

Resources predominantly support the expansion of the number of enrolled students as well as an increase in course offerings as USNCC progresses towards full operational
capability by 2026. As an accredited education institute, USNCC will be responsible for all academic related support and execution infrastructure. USNCC is operating through a
consortium model with the top academic programs in the country, which specialize in professional concentration and general education programs that meet the needs of the naval
services. The USNCC-led consortium will expand to up to twenty partner institutions by the end of FY 2028. The USNCC is responsible for designing world-class programs based
on the feedback provided by the naval operating forces.

Naval Education Training Command (NETC)/Naval Education and Training Professional Development Center (NETPDC) supports the North Atlantic Treaty Organization
Defense College is a Joint North Atlantic Treaty Organization effort staffed by the various military services of the participating countries. Funding for this program provides for
student travel and per diem required by the curriculum and administrative costs such as official telephone calls and mail delivery for assigned U.S. students.

         The Officer Short Courses provides payment for tuition and travel for Officers in the Federal Executive Fellowship, Foreign War College, and Executive Fellowship
         programs.



                                                                                                                                                               $$, $$a8eb719b172d86cc5e18dff238403134c0d3d1776385c3f44a0b857faeab2a51$$, $$O&M/FY26/Navy/OMN_Book.pdf$$, NULL, $$2026-05-07T23:02:19.21198+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_activity_years (activity_code, fiscal_year, service, appropriation, ba, sag_short_code, title, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$OM_NAVY_X_470$$, 2026, $$Navy$$, $$OM_NAVY$$, NULL, NULL, $$Department of the Navy$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$, 3B3K
         525                                                                                                                                                        (Page 1 of 14)
                                                                           Department of the Navy
                                                                   FY 2026 President's Budget Submission
                                                                      Operation and Maintenance, Navy
                                                                   Budget Activity: Training and Recruiting
                                                             Activity Group: Basic Skills And Advanced Training
                                                      Detail by Subactivity Group: Professional Development Education
         The Graduate Education Program broadens opportunities for Sailors to pursue advanced degrees by providing tuition and financial support for graduate education. This
         program includes Graduate Education Vouchers (GEV), which fund Unrestricted Line (URL) officers to attend off-duty graduate education courses, Advanced Education
         Vouchers (AEV), which provide funding for selected enlisted personnel to obtain undergraduate and graduate degrees.

*The Armed Forces Health Professions Program provides for education and training cost of Navy Reserve Officers that are scholarship program participants of the Armed Forces
Health Professions Scholarship Program (AFHPSP) and Financial Assistance Program (FAP) residencies. The funding supports the tuition, fees, books, and other reimbursable
expenses for AFHPSP and FAP participants. Additionally, the Armed Forces Active-Duty Health Professions Loan Repayment Program (HPLRP) offers financial support to repay
education loans for providers currently on active duty.

*Naval Medical Forces Support Command (NMFSC) and its Echelon IV commands execute medical readiness education and training for Navy Medicine assets, the Fleet, and
Fleet Marine Forces. In support of Force Generation and Force Development, the Command implements over 124 courses of instruction to generate officer and enlisted
professionals for shipboard medical care, aviation operations, Marine Corps force integration around the globe, and for shore-based medical treatment facilities. Additionally, it's
Medical Modeling and Simulation (MM&S) program office centrally manages and validates the integration of MM&S tools and services across a broad spectrum of training
platforms, learning environments, and delivery modalities, providing the medical enterprise and fleet with standardized capabilities and vetting of emerging technologies.

NMFSC executes training for and provides evaluation and training certification of the readiness of all deployable medical platforms for operational use, to include Expeditionary
Medical Facilities (EMF), Expeditionary Medical Units (EMU), Forward Deployable Preventative Medicine Units (FDPMU), Expeditionary Medicine (EXMED) platforms, and
Role 2 Platforms. It is also charged to develop the Role 2 Light Maneuver platform for operational availability to ground forces.

The Commands provide integral service-specific expertise and support to all joint medical training environments, including oversight of Navy medical instructors and students at
the Defense Health Agency's Medical Training and Education Campus where basic "A" schools and the majority of more advanced technical "C" schools are located. NMFSC also
represents Navy Medicine interests to the Inter-Service Training Review Organization and Inter-service Training Advisory Board.

The professional medical education and training enterprise provides the Navy with qualified medical officer accessions, graduate and post-graduate officer education, residencies,
and internships, and career-critical professional development and continuing medical education.

Navy Medicine provides direct specialized medical training services to operational Navy Line forces to include aviation, undersea and dive medical screening, hyperbaric
treatment, aviation environmental and survival training for all Navy aircrew personnel, and special operations medical training support for the joint Special Operations Forces
community.

*The Armed Forces Health Professions Program and Naval Medical Forces Support Command (NMFSC) funding is transferred to new LI 1C1M, Medical Readiness in FY 2026
to consolidate Navy Medical Readiness resources into a single Budget Activity/Sub-Activity Group to ensure consistency with other Services.



II. Force Structure Summary:

This program funds the Naval War College, the Naval Postgraduate School, Navy Professional Military Education, United States Naval Community College, Graduate Education
Programs including the Navy Staff Program, Graduate Education Vouchers, Advanced Education Vouchers and Accelerate to Excellence and Officer Short Courses. Officer Short
                                                                                                                                                     $$, $$955d280423323f67af9891cff27be9fc47793814f00391787f0a6f2b7ab086f8$$, $$O&M/FY26/Navy/OMN_Book.pdf$$, NULL, $$2026-05-07T23:02:19.21198+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_activity_years (activity_code, fiscal_year, service, appropriation, ba, sag_short_code, title, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$OM_NAVY_X_471$$, 2026, $$Navy$$, $$OM_NAVY$$, NULL, NULL, $$Department of the Navy$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$, 3B3K
        526                                                                                                                                               (Page 2 of 14)
                                                                            Department of the Navy
                                                                    FY 2026 President's Budget Submission
                                                                       Operation and Maintenance, Navy
                                                                    Budget Activity: Training and Recruiting
                                                              Activity Group: Basic Skills And Advanced Training
                                                       Detail by Subactivity Group: Professional Development Education
Courses include the following: North Atlantic Treaty Organization Defense College, Executive Training, Federal Executive Fellowship, Foreign War & Staff Colleges, Flag
Language Training, Foreign Services Institute and Shore Station Command Seminar.

The AFHPSP, established by 10 U.S.C. 2121, is an Individual Ready Reserve Program for students accepted to, or enrolled in, an accredited training program leading to a health
professions degree in medicine, dentistry, optometry, clinical psychology, and master's degrees as physician assistants. The FAP, established by 10 U.S.C. 2121, is an Individual
Ready Reserve Program for physicians or dentist currently accepted to, or enrolled in, an accredited residency or fellowship program progressing toward a medical or dental
specialty which has been designated as critical to the Department of Defense. The HPLRP is a direct accession and retention program to maintain adequate numbers of
commissioned officers of the armed forces on active duty who are qualified health professionals in specific specialties.

Designated as the Training Agent for the Navy Medicine enterprise, NMFSC and subordinate commands, centers, and institutes control curriculum for 124 Navy Medicine
education and training programs while quotas managers are responsible for student management of 210 Officer and Enlisted medical courses taught at 611 locations. The Medical
Modeling and Simulation (MM&S) program office centralizes and standardizes the integration of MM&S emerging technologies across a broad spectrum of training platforms,
learning environments, and delivery modalities, to provide the medical enterprise and fleet with Live Virtual and Constructive (LVC) training to increase survivability and
readiness while reducing risk and cost. The Naval Medical Forces Support Command supports EXMED platform deployment readiness assessment through training of SMEs and
observation team members, development of training curriculum content and standards, validation of material used in performance evaluations and direct participation in platform
assessment. The Echelon IV Commands provide oversight of Navy medical instructors and students at multiple locations including schoolhouses in Groton, Connecticut, Bethesda,
Maryland, Pensacola Florida, and San Diego California, as well as the San Antonio, Texas Medical Training and Education Campus where basic ("A"-School) and many advanced
technical schools ("C"-Schools) are located. The professional medical education and training enterprise also provides the Navy with qualified medical officer accessions, graduate
and post-graduate officer education, residencies, and internships, and career-critical professional development and continuing medical education. Corpsman and medical officers
receive advanced technical education with specialized medical professionals to include qualified independent duty corpsman for assignment to surface and subsurface platforms,
accredited medical specialists for shore-based medical treatment, and trauma-trained corpsman for the operational environment. Medical officers receive specialization for
undersea, surface, radiation, and dental operational requirements. Also provided are direct specialized medical training services to operational Navy Line forces to include aviation
medical screening, hyperbaric treatment, aviation environmental and survival training, and special operations medical training support.




